/**
 * AuthContext.jsx
 * ─────────────────────────────────────────────────────────────
 * Contexto global de autenticación.
 * Provee al árbol de componentes: usuario, token, login, logout.
 *
 * Persiste la sesión en localStorage para que el usuario no
 * tenga que iniciar sesión al recargar la página.
 */

import { createContext, useContext, useState } from 'react'

const AuthContext = createContext(null)

export const AuthProvider = ({ children }) => {
  const [user,  setUser]  = useState(() => {
    try {
      const saved = localStorage.getItem('finanzas_user')
      return saved ? JSON.parse(saved) : null
    } catch { return null }
  })

  const [token, setToken] = useState(
    () => localStorage.getItem('finanzas_token') || null
  )

  /**
   * Guarda el usuario y token en estado y localStorage.
   * @param {object} userData — { id, name, email }
   * @param {string} authToken — JWT
   */
  const login = (userData, authToken) => {
    setUser(userData)
    setToken(authToken)
    localStorage.setItem('finanzas_user',  JSON.stringify(userData))
    localStorage.setItem('finanzas_token', authToken)
  }

  /** Limpia el estado y localStorage. */
  const logout = () => {
    setUser(null)
    setToken(null)
    localStorage.removeItem('finanzas_user')
    localStorage.removeItem('finanzas_token')
  }

  return (
    <AuthContext.Provider value={{
      user,
      token,
      login,
      logout,
      isAuth: !!token,
    }}>
      {children}
    </AuthContext.Provider>
  )
}

/**
 * Hook para consumir el contexto de autenticación.
 * Lanza error si se usa fuera de AuthProvider.
 */
export const useAuth = () => {
  const ctx = useContext(AuthContext)
  if (!ctx) throw new Error('useAuth debe usarse dentro de <AuthProvider>')
  return ctx
}
